import{_ as a}from"./chunks/lekt0401.veXHzs2X.js";import{_ as p,o as i,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung003.jpg",c=JSON.parse('{"title":"Übung Lektion 4","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung04.md","filePath":"lektionen/uebung04.md"}'),s={name:"lektionen/uebung04.md"};function u(d,e,l,o,k,m){return i(),t("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-4" tabindex="-1">Übung Lektion 4 <a class="header-anchor" href="#ubung-lektion-4" aria-label="Permalink to &quot;Übung Lektion 4&quot;">​</a></h1><p>A) Bilden Sie mündlich mit folgenden Wörtern Fragen nach dem Schema viṣṇuḥ kaḥ (विष्णुः कः) und beantworten Sie die Fragen auf Sanskrit:</p><p>śruti, śiva, brāhmaṇa, dvija (plural), indrāṇī, dhenu, tulādhara, kālidāsa</p><p>= श्रुति, शिव, ब्राह्मण, द्विज (बहुवचनम्), इन्द्राणी, धेनु, तुलाधर, कालिदास</p><p>śrutiḥ kā? vedaḥ śrutiḥ.</p><p>श्रुतिः का । वेदः श्रुतिः ।</p><p>śivaḥ kaḥ? īśvaraḥ śivaḥ.</p><p>शिवः कः । ईश्वरः शिवः ।</p><p>brāhmaṇaḥ kaḥ? dvijo brāhmaṇaḥ.</p><p>ब्राह्मणः कः । द्विजो ब्राह्मणः ।</p><p>dvijāḥ ke? brāhmānakṣatriyavaiśyā dvijāḥ.</p><p>द्विजाः के । ब्राह्मणक्षत्रियवैश्या द्विजाः ।</p><p>indrāṇī kā? devīndrāṇī.</p><p>इन्द्राणी का । देवीन्द्राणी ।</p><p>dhenuḥ kā? paśur dhenuḥ.</p><p>धेनुः का । पशुर्धेनुः ।</p><p>tulādharaḥ kaḥ? vaiśyas tulādharaḥ.</p><p>तुलाधरः कः । वैश्यस्तुलाधरः ।</p><p>kālidāsaḥ kaḥ? kaviḥ kālidāsaḥ.</p><p>कालिदासः कः । कविः कालिदासः ॥</p><p>B) Bilden Sie zur folgenden Leseübung Fragen nach dem Muster etat kim (एतत्किम्) und beantworten Sie die Fragen mit den angegebenen Wörtern und Demonstrativpronomen z.B. eṣa bālaḥ (एष बालः):</p><p><img src="'+a+'" alt=""></p><p>eṣa kaḥ? eṣa gajaḥ / ayaṃ gajaḥ / sa gajaḥ.</p><p>एष कः । एष गजः । अयं गजः । स गजः ।</p><p>eṣā kā? eṣā bālā / iyaṃ bālā / sā bālā.</p><p>एषा का । एषा बाला । इयं बाला । सा बाला ।</p><p>etad kim? eṣa śukaḥ.</p><p>एतत्किम् । एष शुकः ।</p><p>etat kim? eṣa kākaḥ.</p><p>एतत्किम् । एष काकः ।</p><p>etat kim? eṣā peṭikā.</p><p>एतत्किम् । एषा पेटिका ।</p><p>etat kim? eṣā lātā.</p><p>एतत्किम् । एषा लाता ।</p><p>etat kim? eṣa pādaḥ.</p><p>एतत्किम् । एष पादः ।</p><p>eṣa kaḥ? eṣa bālaḥ.</p><p>एष कः । एष बालः ।</p><p>etat kim? eṣā pipīlikā.</p><p>एतत्किम् । एषा पिपीलिका ॥</p><p><img src="'+r+'" alt=""><br> Abb.: etat kim? eṣa kākaḥ.  एतत्किम् | एष काकः ||<br> Glanzkrähen (<em>Corvus splendens</em>), Rājasthān (राजस्थान)<br> [Bildquelle: Duncan Wright / Wikipedia. -- GNU FDLizenz]</p>',42)])])}const h=p(s,[["render",u]]);export{c as __pageData,h as default};
